package arch.day7;

import java.util.ArrayList;
import java.util.List;

public class Day7Intermediate {
    static class Box {
        final int w;
        final int h;
        final int d;
        Box() {
            this(1, 1, 1);
        }
        Box(int w, int h, int d) {
            this.w = w;
            this.h = h;
            this.d = d;
        }
        @Override
        public String toString() {
            return w + "x" + h + "x" + d;
        }
    }
    static class Vault {
        private final double balance;
        Vault(double balance) {
            this.balance = balance;
        }
        String describe() {
            return "Vault balance=" + balance;
        }
    }
    abstract static class Shape {
        final String color;
        Shape(String color) {
            this.color = color;
        }
        abstract double area();
    }
    static class Circle extends Shape {
        final double radius;
        Circle(String color, double radius) {
            super(color);
            this.radius = radius;
        }
        @Override
        double area() {
            return 3.141592653589793 * radius * radius;
        }
    }
    static class Rectangle extends Shape {
        final double width;
        final double height;
        Rectangle(String color, double width, double height) {
            super(color);
            this.width = width;
            this.height = height;
        }
        @Override
        double area() {
            return width * height;
        }
    }
    static void scenario1() {
        System.out.println("--- Scenario 1: constructor chaining ---");
        Box cube = new Box();
        System.out.println("default box -> " + cube);
    }
    static void scenario2() {
        System.out.println("--- Scenario 2: private field via behaviour ---");
        Vault v = new Vault(250.0);
        System.out.println(v.describe());
        System.out.println("lesson: callers use methods, not raw fields");
    }
    static void scenario3() {
        System.out.println("--- Scenario 3: polymorphic collection ---");
        List<Shape> shapes = new ArrayList<>();
        shapes.add(new Circle("red", 3));
        shapes.add(new Rectangle("blue", 4, 5));
        for (Shape s : shapes) {
            System.out.println(s.color + " area=" + s.area());
        }
    }
    static void scenario4() {
        System.out.println("--- Scenario 4: instanceof vs virtual call ---");
        Shape s = new Circle("green", 2);
        System.out.println("virtual area=" + s.area());
        System.out.println("prefer polymorphism; use instanceof only when necessary");
    }
    public static void main(String[] args) {
        System.out.println("warmup: Day7 intermediate OOP lab");
        scenario1();
        scenario2();
        scenario3();
        scenario4();
        System.out.println("footer: align with Shape assignment hierarchy");
    }
}

package arch.day7;

/**
 * Day 7 advanced: Shape hierarchy demo, override vs overload table, encapsulation checklist.
 */
public class Day7Advanced {

    abstract static class Shape {
        final String color;

        Shape(String color) {
            this.color = color;
        }

        abstract double area();

        abstract String kind();

        String label() {
            return kind() + "(" + color + ")";
        }
    }

    static class Circle extends Shape {
        final double radius;

        Circle(String color, double radius) {
            super(color);
            this.radius = radius;
        }

        @Override
        String kind() {
            return "Circle";
        }

        @Override
        double area() {
            return 3.141592653589793 * radius * radius;
        }
    }

    static class Rectangle extends Shape {
        final double width;
        final double height;

        Rectangle(String color, double width, double height) {
            super(color);
            this.width = width;
            this.height = height;
        }

        @Override
        String kind() {
            return "Rectangle";
        }

        @Override
        double area() {
            return width * height;
        }
    }

    static void spacer() {
        System.out.println("---");
    }

    static void block1() {
        System.out.println("=== Block 1: concrete shapes ===");
        Shape disk = new Circle("cyan", 2.5);
        Shape tile = new Rectangle("gray", 3, 4);
        System.out.println(disk.label() + " area=" + disk.area());
        System.out.println(tile.label() + " area=" + tile.area());
        System.out.println("note: assignment used double radius PI constant inline");
        System.out.println();
    }

    static void block2() {
        System.out.println("=== Block 2: override vs overload cues ===");
        System.out.println("concept              | signal");
        System.out.println("---------------------|-----------------------------");
        System.out.println("override             | same instance signature in subclass");
        System.out.println("overload             | same name, different params");
        System.out.println("hide static          | static methods do not override");
        System.out.println("final method         | cannot override downstream");
        System.out.println("abstract method      | must implement in concrete class");
        System.out.println();
    }

    static void block3() {
        System.out.println("=== Block 3: design checklist ===");
        System.out.println("1) private fields for mutable state");
        System.out.println("2) constructors reject illegal arguments");
        System.out.println("3) equals/hashCode paired for value objects");
        System.out.println("4) prefer interfaces for cross-cutting capabilities");
        System.out.println("5) document extension points with final or sealed intent");
        System.out.println("6) polymorphic lists over instanceof ladders");
        System.out.println("review complete");
    }

    public static void main(String[] args) {
        System.out.println("banner: Day7 advanced OOP lab");
        block1();
        spacer();
        block2();
        spacer();
        block3();
        System.out.println("postscript: next step -- BankAccount invariants from assignment");
    }
}

