package arch.day7;

/**
 * Day 7 exercise — maps to assignments_phase1.json Day 7 prompts.
 */
public class Day7Exercise {

    static class Box {
        final int w;
        final int h;
        final int d;

        Box() {
            this(1, 1, 1);
        }

        Box(int w, int h, int d) {
            this.w = w;
            this.h = h;
            this.d = d;
        }

        @Override
        public String toString() {
            return w + "x" + h + "x" + d;
        }
    }

    static class BankAccount {
        private double balance;

        BankAccount(double initial) {
            if (initial < 0) {
                throw new IllegalArgumentException("bad initial");
            }
            balance = initial;
        }

        void deposit(double amount) {
            if (amount <= 0) {
                throw new IllegalArgumentException("bad deposit");
            }
            balance += amount;
        }

        boolean withdraw(double amount) {
            if (amount <= 0 || amount > balance) {
                return false;
            }
            balance -= amount;
            return true;
        }

        double getBalance() {
            return balance;
        }
    }

    static class Shape {
        String color;

        Shape(String color) {
            this.color = color;
        }

        double area() {
            return 0.0;
        }
    }

    static class Circle extends Shape {
        double radius;

        Circle(String color, double radius) {
            super(color);
            this.radius = radius;
        }

        @Override
        double area() {
            return 3.141592653589793 * radius * radius;
        }
    }

    static class Rectangle extends Shape {
        double width;
        double height;

        Rectangle(String color, double width, double height) {
            super(color);
            this.width = width;
            this.height = height;
        }

        @Override
        double area() {
            return width * height;
        }
    }

    public static void main(String[] args) {
        System.out.println("1) Encapsulation: hide state, expose controlled behaviour");
        System.out.println("2) Inheritance: extend specialised types from general ones");
        System.out.println("3) Polymorphism: one reference type, many runtime implementations");
        System.out.println("4) Abstraction: depend on contracts not concrete internals");

        System.out.println("box=" + new Box());

        BankAccount acct = new BankAccount(100.0);
        System.out.println("balance=" + acct.getBalance());
        acct.deposit(25.0);
        System.out.println("balance=" + acct.getBalance());
        System.out.println("withdraw200=" + acct.withdraw(200.0));
        System.out.println("balance=" + acct.getBalance());
        System.out.println("withdraw50=" + acct.withdraw(50.0));
        System.out.println("balance=" + acct.getBalance());

        // Polymorphism: single loop over Shape references calls correct area() implementations.
        Shape[] shapes = {new Circle("red", 3), new Rectangle("blue", 4, 5)};
        for (Shape s : shapes) {
            System.out.println("shape-area:" + s.area());
        }
    }
}

